mapper.select:
SELECT r.id, r.serial_num, r.transaction_type, r.payment_type, r.amount,
       r.paid_amount, r.status, r.house_id, r.user_id, r.org_id, r.company_id,
       r.item_group, r.item_code, r.transaction_time, r.operator_id, r.notes,
       r.original_record_id, r.invoice_no,
       b.room_num, u.user_name
FROM pr_transaction_record r
LEFT JOIN pr_house b ON r.house_id = b.id
LEFT JOIN pr_user u ON r.user_id = u.id
WHERE 1=1

    AND r.company_id = #{companyId}


    AND r.org_id = #{orgId}


    AND b.building_id = #{buildingId}


    AND b.unit_code = #{unitCode}


    AND r.transaction_time >= #{startTime}


    AND r.transaction_time <= #{endTime}


    AND r.status = #{status}


    AND (b.room_num LIKE CONCAT('%', #{search}, '%')
         OR u.user_name LIKE CONCAT('%', #{search}, '%')
         OR r.serial_num LIKE CONCAT('%', #{search}, '%'))

ORDER BY r.transaction_time DESC

SELECT COUNT(*) AS totalTransactions, SUM(CASE WHEN transaction_type = 1 THEN 1 ELSE 0 END) AS chargeCount, SUM(CASE WHEN transaction_type = 2 THEN 1 ELSE 0 END) AS refundCount, SUM(CASE WHEN transaction_type = 3 THEN 1 ELSE 0 END) AS transferCount, SUM(CASE WHEN transaction_type = 1 THEN paid_amount ELSE 0 END) AS chargeAmount, SUM(CASE WHEN transaction_type = 2 THEN amount ELSE 0 END) AS refundAmount, SUM(CASE WHEN status = 1 THEN 1 ELSE 0 END) AS revokedCount, SUM(CASE WHEN status = 2 THEN 1 ELSE 0 END) AS invalidCount FROM pr_transaction_record WHERE company_id = #{companyId} AND org_id = #{orgId}
AND transaction_time >= #{startTime}
AND transaction_time <= #{endTime}

SELECT COUNT(*) AS receivedCount, SUM(paid_amount) AS totalReceived, SUM(CASE WHEN payment_type = 1 THEN paid_amount ELSE 0 END) AS cashAmount, SUM(CASE WHEN payment_type = 2 THEN paid_amount ELSE 0 END) AS wechatAmount, SUM(CASE WHEN payment_type = 3 THEN paid_amount ELSE 0 END) AS alipayAmount, SUM(CASE WHEN payment_type = 4 THEN paid_amount ELSE 0 END) AS cardAmount FROM pr_transaction_record WHERE company_id = #{companyId} AND org_id = #{orgId} AND transaction_type = 1 AND status = 0
AND transaction_time >= #{startTime}
AND transaction_time <= #{endTime}

SELECT a.id, a.meter_id, a.type, a.card_type, a.create_by, a.create_time,
       s.nick_name AS createByName, d.name AS buildingName,
       h.unit_code AS unitCode, h.room_num AS roomNum,
       o.name AS orgName
FROM pr_operate_card_log a
LEFT JOIN sys_user s ON a.create_by = s.id
LEFT JOIN pr_heat_valve_archive v ON a.meter_id = v.id
LEFT JOIN pr_house h ON h.id = v.house_id
LEFT JOIN pr_building d ON d.id = h.building_id
LEFT JOIN sys_organization o ON a.org_id = o.id
WHERE a.company_id = #{companyId}
AND a.org_id = #{orgId}
AND h.building_id = #{buildingId}
AND a.type = #{type}
AND a.create_by = #{createBy}
AND a.create_time >= #{startTime}
AND a.create_time <= #{endTime}
AND (h.room_num LIKE CONCAT('%',#{search},'%') OR v.meter_num LIKE CONCAT('%',#{search},'%'))
ORDER BY a.create_time DESC

SELECT s.id, s.user_name
FROM pr_operate_card_log a
LEFT JOIN sys_user s ON a.create_by = s.id
WHERE a.company_id = #{companyId}
AND a.org_id = #{orgId}
GROUP BY a.create_by
